<template>
	<view class="siter-box">
		<view class="my-siter">
			<view class="bg-box" :style="{
				backgroundImage:'url('+$util.img('/statics/uni/img/team/my_siter_img_bg.png')+')'
			}">
				<view class="on-open" v-if="userinfo.is_team_head == 0">
					未开通
				</view>
				<view class="on-open" v-if="userinfo.is_team_head == 1" style="color: #fff;">
					已开通
				</view>
				<view class="user-box">
					<image class="user-avatar" :src="userinfo.headurl_img" mode="aspectFit"></image>
					<view class="right">
						<text class="name">
							{{userinfo.company}}
						</text>
						<text class="no-tips">
							{{userinfo.is_team_head == 1?'您已开通团长':'您尚未开通团长权益'}}
						</text>
					</view>
				</view>

				<view class="bottom-tips">
					开通团长权益 尊享3大精选权益
				</view>
			</view>



			<view class="open-box">
				<view class="funciton-box">
					<view class="item">
						<view class="icon-box">
							<image class="icon" :src="$util.img('/statics/uni/img/team/tzfy.svg')"
								mode="aspectFit"></image>
						</view>
						<text class="header">
							永久返佣
						</text>
						<text class="tips">
							仅需一次推广
						</text>
					</view>



					<view class="item">
						<view class="icon-box">
							<image class="icon" :src="$util.img('/statics/uni/img/team/tztx.svg')"
								mode="aspectFit"></image>
						</view>
						<text class="header">
							极速提现
						</text>
						<text class="tips">
							佣金结算秒到账
						</text>
					</view>
					<view class="item">
						<view class="icon-box">
							<image class="icon" :src="$util.img('/statics/uni/img/team/tzkf.svg')"
								mode="aspectFit"></image>
						</view>
						<text class="header">
							专属客服
						</text>
						<text class="tips">
							极速响应
						</text>
					</view>

				</view>


				<view class="submit-btn" v-if="userinfo.is_team_head==0" @click="openmeal">
					立即开通 / ¥{{price}}永久适用
				</view>
				<view class="submit-btn" v-if="userinfo.is_team_head ==1" style="background: #ccc;color: #fff;">
					已开通
				</view>
				<view class="user-need-know">
					{{' 开通即代表已知晓并同意'}}
					<text class="link" @click="xieyi">《团长服务协议》</text>
				</view>
			</view>


			<view class="explain-box">
				<view class="explain-title">
					团长权益说明
				</view>

				<view class="explain-item">
					<view class="label">
						<image class="icon" :src="$util.img('/statics/uni/img/team/icon_quanyi.svg')"
							mode="aspectFit"></image>
						<text class="title">
							永久返佣：
						</text>
					</view>
					<text class="text">
						团长邀请的团员消费和升级会员，团长都会收到奖励
					</text>
				</view>


				<view class="explain-item">
					<view class="label">
						<image class="icon" :src="$util.img('/statics/uni/img/team/icon_quanyi.svg')"
							mode="aspectFit"></image>
						<text class="title">
							极速提现：
						</text>
					</view>
					<text class="text">
						收到的佣金可直接提现到微信或支付宝
					</text>
				</view>


				<view class="explain-item">
					<view class="label">
						<image class="icon" :src="$util.img('/statics/uni/img/team/icon_quanyi.svg')"
							mode="aspectFit"></image>
						<text class="title">
							专属顾问：
						</text>
					</view>
					<text class="text">
						绑定专属顾问，优惠、活动实时通知，享受收益更简单。
					</text>
				</view>
			</view>


		</view>


		<u-modal v-model="input_pwd" @confirm="toPay" ref="trade_password_box" :async-close="true" title="交易密码"
			:mask-close-able="true">
			<u-message-input v-if="input_pwd"  :focus="true" @change="inputPwdChange" @finish="inputPwdFinish" :dot-fill="true"
				:maxlength="6" mode="bottomLine"></u-message-input>
		</u-modal>
	</view>
</template>

<script>
	export default {


		data() {
			return {


				price: '', //团长开通金额
				trade_password: '',
				input_pwd: false,
			}
		},
		onLoad() {
			this.loadData();
		},

		methods: {
			openmeal() {
				if (this.userinfo.is_team_head == 1) {
					this.$util.msg('已开通团长')
				} else {
					this.input_pwd = true
				}
			},
			xieyi() {
				//团长服务协议
			},
			async loadData() {
				uni.showLoading({
					mask: true,
					title: '加载中...',

				})

				await this.$u.api.openteamConfig({})
					.then(res => {

						this.price = res.price

					}).catch(res => {})

				uni.hideLoading()
			},


			async toPay() {
				//交易密码输入完成

				if (this.input_finish) {


					if (this.qz == '') {
						this.$util.msg('请输入域名前缀');
						return;
					}


					uni.showLoading({
						mask: true,
						title: '加载中...',

					})
					await this.$u.api.openteam({
							trade_password: this.trade_password,
							price: this.price,
						})
						.then(res => {

							this.$util.msg('开通成功')
							setTimeout(() => {
								this.$util.on('/pages/ucenter/index');
							}, 1000)


						}).catch(res => {})

					uni.hideLoading()

				} else {
					this.$util.msg('请输入完整交易密码');

				}
				this.$refs.trade_password_box.clearLoading()
			},
			inputPwdChange(value) {
				this.input_finish = false;
			},
			inputPwdFinish(value) {
				this.trade_password = value
				this.input_finish = true;
			},

		}
	}
</script>

